// @ts-check
import { defineConfig } from 'astro/config';
import react from '@astrojs/react';

// The Weft hub deploys to the domain ROOT of its own subdomain (IA §1.3, §1.4):
//   site:  https://weft.foundryside.dev
//   base:  '/'   (no subpath — every member site is a domain root)
// Cross-subdomain links to members are ABSOLUTE https://{member}.foundryside.dev
// URLs (generated by the shared @weft/site-kit data), so no base-path gymnastics.
export default defineConfig({
  site: 'https://weft.foundryside.dev',
  base: '/',
  integrations: [react()],
});
